/// <reference lib="webworker" />

export interface OcrWorkerRequest {
  type: 'recognize';
  imageData: ImageData;
}

export interface OcrWorkerResponse {
  type: 'result' | 'error';
  blocks?: Array<{
    id: string;
    text: string;
    bbox: { x: number; y: number; width: number; height: number };
    confidence: number;
  }>;
  error?: string;
}

/** Lightweight OCR stub — runs in Web Worker to avoid blocking main thread */
self.onmessage = (e: MessageEvent<OcrWorkerRequest>) => {
  if (e.data.type === 'recognize') {
    const { width, height } = e.data.imageData;
    const response: OcrWorkerResponse = {
      type: 'result',
      blocks: [
        {
          id: 'ocr-1',
          text: '极致体验',
          bbox: { x: width * 0.3, y: height * 0.4, width: width * 0.4, height: height * 0.1 },
          confidence: 0.92,
        },
      ],
    };
    self.postMessage(response);
  }
};
